def gen(rng, size):
    sn = rng.randrange(1, min(20, max(2, size)) + 1)
    s = ''.join(rng.choice('ab') for _ in range(sn))
    pchars = []
    while len(''.join(pchars)) < rng.randrange(1, min(20, max(2, size)) + 1):
        tok = rng.choice(['a', 'b', '.'])
        pchars.append(tok)
        if rng.random() < 0.4:
            pchars.append('*')
    p = ''.join(pchars)[:20]
    if not p:
        p = 'a'
    if p[0] == '*':
        p = 'a' + p[1:]
    return [s, p]

